insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIA'and edp.apellido1='MARQUEZ'and apellido2='ANDRADE'),'2018-01-25','-AMALIA: HABLO CON LA PROVIDENCIA , EL INGRESO AUN NO SE HA EFECTUADO. ESTÁ PENDIENTE DEL ALTA DE PSIQUIATRIA EN LA UDAC. YA TENEMOS LA RESOLUCION DE LA UNIDAD DE RECURSOS. SE HABLÓ CON LA TS DE CSS PLASENCIA Y EL TRASLADO SE HACE DESDE ALLÍ. QUEDO CON LA TS DE LA PROVIDENCIA QUE NOS AVISARÁ EL DIA DEL INGRESO PARA QUE PROCEDAMOS A REALIZAR EL ABONO DEL 75% DE LA PLAZA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2018-01-25','(Pedro) Reunión en CRR con Javier y Beatriz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2018-01-25','(Pedro)Conversación con Elena, T. Soc. de Las Cumbres. +++REfiere que Margarita se encuentra bien, aunque desde hace unas semanas se muestra muy demandante en cuanto a sus tutores. +++Se le informa de que se ha decidido, dada la falta de respuesta del...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2018-01-26','(Pedro) Conversación con Elena (Las Cumbres). +++El tema de la reserva de plaza está resuelto, porque ya tienen un número de cuenta donde ingresarlo. +++Traslado: necesitan cerrar las cuentas de este me hoy, antes de las 9:00. Insiste en que si vamos a pedirle realizar el traslado a ellos o no para incluir dicho coste en la facturación. SE le plantea que no tengo respuesta todavía a ello y que si no es posible hacer una factura aparte, en caso de hacerlo así,ya en febrero. La respeusta es que no se puede facturar ya que Margarita no será ya residente. +++ALTERNATIVA: incluir en la factura los 600€ de traslado y, en caso de que finalemte no lo hagan ellos, hacer una devolución de ese dinero. SE acepta esta alternativa al no saber si va a ser posible desplazarnos allí para traerla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2018-01-26','(Pedro). Conversación con María Chávez, T. Soc. de Vva.del Fresno (924-427000/250 y 924-427046).Correo:ssasb.vdelfresno@gmail.com> +++Está comunicando. Volver a llamar.','2');
